import type { PlayerContext, TanStackPlugin } from '@tanstack-player/core'

/** Bookmark data model */
export interface Bookmark {
  id: string
  time: number
  label?: string
  createdAt: number
}

/** Events emitted by the bookmark plugin */
export const BookmarkEvent = {
  ADDED: 'bookmark:added',
  REMOVED: 'bookmark:removed',
} as const

/**
 * Bookmark plugin — stores timestamps with optional labels,
 * allows seeking to bookmarks, and emits events.
 */
export class BookmarkPlugin implements TanStackPlugin {
  readonly name = 'bookmark'
  private ctx: PlayerContext | null = null
  private bookmarks: Bookmark[] = []
  private idCounter = 0

  setup(ctx: PlayerContext): void {
    this.ctx = ctx
  }

  destroy(): void {
    this.bookmarks = []
    this.ctx = null
  }

  /** Add a bookmark at the current playback position (or at a specific time) */
  addBookmark(label?: string, time?: number): Bookmark {
    const actualTime = time ?? this.ctx?.controller.getCurrentTime() ?? 0

    const bookmark: Bookmark = {
      id: `bm_${++this.idCounter}_${Date.now()}`,
      time: actualTime,
      label,
      createdAt: Date.now(),
    }

    this.bookmarks.push(bookmark)
    this.bookmarks.sort((a, b) => a.time - b.time)

    this.ctx?.eventBus.emit(BookmarkEvent.ADDED, bookmark as any)

    return bookmark
  }

  /** Remove a bookmark by ID */
  removeBookmark(id: string): boolean {
    const index = this.bookmarks.findIndex((b) => b.id === id)
    if (index === -1) return false

    const [removed] = this.bookmarks.splice(index, 1)
    this.ctx?.eventBus.emit(BookmarkEvent.REMOVED, removed as any)

    return true
  }

  /** Get all bookmarks sorted by time */
  getBookmarks(): Bookmark[] {
    return [...this.bookmarks]
  }

  /** Seek to a specific bookmark */
  seekToBookmark(id: string): boolean {
    const bookmark = this.bookmarks.find((b) => b.id === id)
    if (!bookmark) return false

    this.ctx?.controller.seek(bookmark.time)
    return true
  }
}

/**
 * Factory function for creating a bookmark plugin instance.
 */
export function createBookmarkPlugin(): BookmarkPlugin {
  return new BookmarkPlugin()
}
